    d_finavalu[offset_24] = kon_myomg*Mgi*(Bmax_myosin-d_initvalu_23-d_initvalu_24)-koff_myomg*d_initvalu_24;
    d_finavalu[offset_25] = kon_sr*d_initvalu_38*(Bmax_SR-d_initvalu_25)-koff_sr*d_initvalu_25;
    J_CaB_cytosol = d_finavalu[offset_19] + d_finavalu[offset_20] + d_finavalu[offset_21] + d_finavalu[offset_22] + d_finavalu[offset_23] + d_finavalu[offset_24] + d_finavalu[offset_25];

    d_finavalu[offset_26] = kon_sll*d_initvalu_36*(Bmax_SLlowj-d_initvalu_26)-koff_sll*d_initvalu_26;
    d_finavalu[offset_27] = kon_sll*d_initvalu_37*(Bmax_SLlowsl-d_initvalu_27)-koff_sll*d_initvalu_27;
    d_finavalu[offset_28] = kon_slh*d_initvalu_36*(Bmax_SLhighj-d_initvalu_28)-koff_slh*d_initvalu_28;
    d_finavalu[offset_29] = kon_slh*d_initvalu_37*(Bmax_SLhighsl-d_initvalu_29)-koff_slh*d_initvalu_29;
    J_CaB_junction = d_finavalu[offset_26]+d_finavalu[offset_28];
    J_CaB_sl = d_finavalu[offset_27]+d_finavalu[offset_29];

    d_finavalu[offset_30] = kon_csqn*d_initvalu_31*(Bmax_Csqn-d_initvalu_30)-koff_csqn*d_initvalu_30;
    oneovervsr = 1.0f/Vsr;
    d_finavalu[offset_31] = J_serca*Vmyo*oneovervsr-(J_SRleak*Vmyo*oneovervsr+J_SRCarel)-d_finavalu[offset_30];

    I_Na_tot_junc = I_Na_junc+I_nabk_junc+3.0f*I_ncx_junc+3.0f*I_nak_junc+I_CaNa_junc;
    I_Na_tot_sl = I_Na_sl+I_nabk_sl+3.0f*I_ncx_sl+3.0f*I_nak_sl+I_CaNa_sl;
    d_finavalu[offset_32] = -I_Na_tot_junc*Cmem/(Vjunc*Frdy)+J_na_juncsl/Vjunc*(d_initvalu_33-d_initvalu_32)-d_finavalu[offset_17];
    oneovervsl = 1.0f/Vsl;
    d_finavalu[offset_33] = -I_Na_tot_sl*Cmem*oneovervsl/Frdy+J_na_juncsl*oneovervsl*(d_initvalu_32-d_initvalu_33)+J_na_slmyo*oneovervsl*(d_initvalu_34-d_initvalu_33)-d_finavalu[offset_18];
    d_finavalu[offset_34] = J_na_slmyo/Vmyo*(d_initvalu_33-d_initvalu_34);

    I_K_tot = I_to+I_kr+I_ks+I_ki-2.0f*I_nak+I_CaK+I_kp;
    d_finavalu[offset_35] = 0.0f;

    I_Ca_tot_junc = I_Ca_junc+I_cabk_junc+I_pca_junc-2.0f*I_ncx_junc;
    I_Ca_tot_sl = I_Ca_sl+I_cabk_sl+I_pca_sl-2.0f*I_ncx_sl;
    d_finavalu[offset_36] = -I_Ca_tot_junc*Cmem/(Vjunc*2.0f*Frdy)+J_ca_juncsl/Vjunc*(d_initvalu_37-d_initvalu_36)
             - J_CaB_junction+(J_SRCarel)*Vsr/Vjunc+J_SRleak*Vmyo/Vjunc;
    d_finavalu[offset_37] = -I_Ca_tot_sl*Cmem/(Vsl*2.0f*Frdy)+J_ca_juncsl/Vsl*(d_initvalu_36-d_initvalu_37)
             + J_ca_slmyo/Vsl*(d_initvalu_38-d_initvalu_37)-J_CaB_sl;
    d_finavalu[offset_38] = -J_serca-J_CaB_cytosol +J_ca_slmyo/Vmyo*(d_initvalu_37-d_initvalu_38);

    state = 1;
    switch(state){
        case 0:
            I_app = 0.0f;
            break;
        case 1:
            if(fmod(timeinst,cycleLength) <= 5.0f){
                I_app = 9.5f;
            }
            else{
                I_app = 0.0f;
            }
            break;
        case 2:
            V_hold = -55.0f;
            V_test = 0.0f;
            if(timeinst>0.5f & timeinst<200.5f){
                V_clamp = V_test;
            }
            else{
                V_clamp = V_hold;
            }
            R_clamp = 0.04f;
            I_app = (V_clamp-d_initvalu_39)/R_clamp;
            break;
    }

    I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
    I_Cl_tot = I_ClCa+I_Clbk;
    I_Ca_tot = I_Ca_tot_junc+I_Ca_tot_sl;
    I_tot = I_Na_tot+I_Cl_tot+I_Ca_tot+I_K_tot;
    d_finavalu[offset_39] = -(I_tot-I_app);

    d_finavalu[offset_41] = 0.0f;
    d_finavalu[offset_42] = 0.0f;
}

inline void kernel_fin_2_func(fp timeinst,
                              __global fp* d_initvalu,
                              __global fp* d_finavalu,
                              int offset_ecc,
                              int offset_Dyad,
                              int offset_SL,
                              int offset_Cyt,
                              __global fp* d_params,
                              __global fp* d_com){

    fp BtotDyad;
    fp CaMKIItotDyad;

    fp Vmyo;
    fp Vdyad;
    fp VSL;

    fp kSLmyo;
    fp k0Boff;
    fp k0Bon;
    fp k2Boff;
    fp k2Bon;

    fp k4Bon;
    fp CaMtotDyad;
    fp Bdyad;
    fp J_cam_dyadSL;
    fp J_ca2cam_dyadSL;
    fp J_ca4cam_dyadSL;
    fp J_cam_SLmyo;
    fp J_ca2cam_SLmyo;
    fp J_ca4cam_SLmyo;

    BtotDyad = d_params[1];
    CaMKIItotDyad = d_params[2];

    d_finavalu[offset_ecc+35] = d_finavalu[offset_ecc+35] + 1e-3f*d_com[0];
    d_finavalu[offset_ecc+36] = d_finavalu[offset_ecc+36] + 1e-3f*d_com[1];
    d_finavalu[offset_ecc+37] = d_finavalu[offset_ecc+37] + 1e-3f*d_com[2];

    Vmyo = 2.1454e-11f;
    Vdyad = 1.7790e-14f;
    VSL = 6.6013e-13f;

    kSLmyo = 8.587e-15f;
    k0Boff = 0.0014f;
    k0Bon = k0Boff/0.2f;
    k2Boff = k0Boff/100.0f;
    k2Bon = k0Bon;

    k4Bon = k0Bon;
    CaMtotDyad = d_initvalu[offset_Dyad+0]
               + d_initvalu[offset_Dyad+1]
               + d_initvalu[offset_Dyad+2]
               + d_initvalu[offset_Dyad+3]
               + d_initvalu[offset_Dyad+4]
               + d_initvalu[offset_Dyad+5]
               + CaMKIItotDyad * (    d_initvalu[offset_Dyad+6]
                                    + d_initvalu[offset_Dyad+7]
                                    + d_initvalu[offset_Dyad+8]
                                    + d_initvalu[offset_Dyad+9])
               + d_initvalu[offset_Dyad+12]
               + d_initvalu[offset_Dyad+13]
               + d_initvalu[offset_Dyad+14];
    Bdyad = BtotDyad - CaMtotDyad;
    J_cam_dyadSL = 1e-3f * (  k0Boff*d_initvalu[offset_Dyad+0] - k0Bon*Bdyad*d_initvalu[offset_SL+0]);
    J_ca2cam_dyadSL = 1e-3f * (  k2Boff*d_initvalu[offset_Dyad+1] - k2Bon*Bdyad*d_initvalu[offset_SL+1]);
    J_ca4cam_dyadSL = 1e-3f * (  k2Boff*d_initvalu[offset_Dyad+2] - k4Bon*Bdyad*d_initvalu[offset_SL+2]);

    J_cam_SLmyo = kSLmyo * (  d_initvalu[offset_SL+0] - d_initvalu[offset_Cyt+0]);
    J_ca2cam_SLmyo = kSLmyo * (  d_initvalu[offset_SL+1] - d_initvalu[offset_Cyt+1]);
    J_ca4cam_SLmyo = kSLmyo * (  d_initvalu[offset_SL+2] - d_initvalu[offset_Cyt+2]);

    d_finavalu[offset_Dyad+0] = d_finavalu[offset_Dyad+0] - J_cam_dyadSL;
    d_finavalu[offset_Dyad+1] = d_finavalu[offset_Dyad+1] - J_ca2cam_dyadSL;
    d_finavalu[offset_Dyad+2] = d_finavalu[offset_Dyad+2] - J_ca4cam_dyadSL;

    d_finavalu[offset_SL+0] = d_finavalu[offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
    d_finavalu[offset_SL+1] = d_finavalu[offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
    d_finavalu[offset_SL+2] = d_finavalu[offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

    d_finavalu[offset_Cyt+0] = d_finavalu[offset_Cyt+0] + J_cam_SLmyo/Vmyo;
    d_finavalu[offset_Cyt+1] = d_finavalu[offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
    d_finavalu[offset_Cyt+2] = d_finavalu[offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;
}

inline void kernel_2_func(fp timeinst,
                          __global fp* initvalu,
                          __global fp* params,
                          __global fp* finavalu,
                          __global fp* com){

    int valu_offset_ecc;
    int valu_offset_Dyad;
    int valu_offset_SL;
    int valu_offset_Cyt;

    int params_offset_Dyad;
    int params_offset_SL;
    int params_offset_Cyt;

    int com_offset_Dyad;
    int com_offset_SL;
    int com_offset_Cyt;

    fp CaDyad;
    fp CaSL;
    fp CaCyt;

    int i;

    valu_offset_ecc = 0;
    valu_offset_Dyad = 46;
    valu_offset_SL = 61;
    valu_offset_Cyt = 76;

    params_offset_Dyad = 0;
    params_offset_SL = 5;
    params_offset_Cyt = 10;

    com_offset_Dyad = 0;
    com_offset_SL = 1;
    com_offset_Cyt = 2;

    kernel_ecc_func(timeinst,
                    initvalu,
                    finavalu,
                    valu_offset_ecc,
                    params);

    CaDyad = initvalu[35]*1e3f;
    kernel_cam_func(timeinst,
                    initvalu,
                    finavalu,
                    valu_offset_Dyad,
                    params,
                    params_offset_Dyad,
                    com,
                    com_offset_Dyad,
                    CaDyad);

    CaSL = initvalu[36]*1e3f;
    kernel_cam_func(timeinst,
                    initvalu,
                    finavalu,
                    valu_offset_SL,
                    params,
                    params_offset_SL,
                    com,
                    com_offset_SL,
                    CaSL);

    CaCyt = initvalu[37]*1e3f;
    kernel_cam_func(timeinst,
                    initvalu,
                    finavalu,
                    valu_offset_Cyt,
                    params,
                    params_offset_Cyt,
                    com,
                    com_offset_Cyt,
                    CaCyt);

    kernel_fin_2_func(timeinst,
                      initvalu,
                      finavalu,
                      valu_offset_ecc,
                      valu_offset_Dyad,
                      valu_offset_SL,
                      valu_offset_Cyt,
                      params,
                      com);

    for(i=0; i<EQUATIONS; i++){
        if (isnan(finavalu[i]) == 1){
            finavalu[i] = 0.0001f;
        }
        else if (isinf(finavalu[i]) == 1){
            finavalu[i] = 0.0001f;
        }
    }
}

inline void embedded_fehlberg_7_8_2(fp h,
                                    fp timeinst,
                                    __global fp* initvalu,
                                    __global fp* finavalu,
                                    __global fp* parameter,
                                    __global fp* error,
                                    __global fp* initvalu_temp,
                                    __global fp* finavalu_temp,
                                    __global fp* com) {

    const fp c_1_11 = 41.0f / 840.0f;
    const fp c6 = 34.0f / 105.0f;
    const fp c_7_8= 9.0f / 35.0f;
    const fp c_9_10 = 9.0f / 280.0f;

    const fp a2 = 2.0f / 27.0f;
    const fp a3 = 1.0f / 9.0f;
    const fp a4 = 1.0f / 6.0f;
    const fp a5 = 5.0f / 12.0f;
    const fp a6 = 1.0f / 2.0f;
    const fp a7 = 5.0f / 6.0f;
    const fp a8 = 1.0f / 6.0f;
    const fp a9 = 2.0f / 3.0f;
    const fp a10 = 1.0f / 3.0f;

    const fp b31 = 1.0f / 36.0f;
    const fp b32 = 3.0f / 36.0f;
    const fp b41 = 1.0f / 24.0f;
    const fp b43 = 3.0f / 24.0f;
    const fp b51 = 20.0f / 48.0f;
    const fp b53 = -75.0f / 48.0f;
    const fp b54 = 75.0f / 48.0f;
    const fp b61 = 1.0f / 20.0f;
    const fp b64 = 5.0f / 20.0f;
    const fp b65 = 4.0f / 20.0f;
    const fp b71 = -25.0f / 108.0f;
    const fp b74 = 125.0f / 108.0f;
    const fp b75 = -260.0f / 108.0f;
    const fp b76 = 250.0f / 108.0f;
    const fp b81 = 31.0f/300.0f;
    const fp b85 = 61.0f/225.0f;
    const fp b86 = -2.0f/9.0f;
    const fp b87 = 13.0f/900.0f;
    const fp b91 = 2.0f;
    const fp b94 = -53.0f/6.0f;
    const fp b95 = 704.0f / 45.0f;
    const fp b96 = -107.0f / 9.0f;
    const fp b97 = 67.0f / 90.0f;
    const fp b98 = 3.0f;
    const fp b10_1 = -91.0f / 108.0f;
    const fp b10_4 = 23.0f / 108.0f;
    const fp b10_5 = -976.0f / 135.0f;
    const fp b10_6 = 311.0f / 54.0f;
    const fp b10_7 = -19.0f / 60.0f;
    const fp b10_8 = 17.0f / 6.0f;
    const fp b10_9 = -1.0f / 12.0f;
    const fp b11_1 = 2383.0f / 4100.0f;
    const fp b11_4 = -341.0f / 164.0f;
    const fp b11_5 = 4496.0f / 1025.0f;
    const fp b11_6 = -301.0f / 82.0f;
    const fp b11_7 = 2133.0f / 4100.0f;
    const fp b11_8 = 45.0f / 82.0f;
    const fp b11_9 = 45.0f / 164.0f;
    const fp b11_10 = 18.0f / 41.0f;
    const fp b12_1 = 3.0f / 205.0f;
    const fp b12_6 = - 6.0f / 41.0f;
    const fp b12_7 = - 3.0f / 205.0f;
    const fp b12_8 = - 3.0f / 41.0f;
    const fp b12_9 = 3.0f / 41.0f;
    const fp b12_10 = 6.0f / 41.0f;
    const fp b13_1 = -1777.0f / 4100.0f;
    const fp b13_4 = -341.0f / 164.0f;
    const fp b13_5 = 4496.0f / 1025.0f;
    const fp b13_6 = -289.0f / 82.0f;
    const fp b13_7 = 2193.0f / 4100.0f;
    const fp b13_8 = 51.0f / 82.0f;
    const fp b13_9 = 33.0f / 164.0f;
    const fp b13_10 = 12.0f / 41.0f;

    const fp err_factor  = -41.0f / 840.0f;

    fp h2_7 = a2 * h;
    fp timeinst_temp;
    int i,j;

    for(j=0; j<13; j++){

        if(j==0){
            timeinst_temp = timeinst;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i];
            }
        }
        else if(j==1){
            timeinst_temp = timeinst+h2_7;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h2_7 * (finavalu_temp[0*EQUATIONS+i]);
            }
        }
        else if(j==2){
            timeinst_temp = timeinst+a3*h;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b31*finavalu_temp[0*EQUATIONS+i] + b32*finavalu_temp[1*EQUATIONS+i]);
            }
        }
        else if(j==3){
            timeinst_temp = timeinst+a4*h;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b41*finavalu_temp[0*EQUATIONS+i] + b43*finavalu_temp[2*EQUATIONS+i]);
            }
        }
        else if(j==4){
            timeinst_temp = timeinst+a5*h;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b51*finavalu_temp[0*EQUATIONS+i] + b53*finavalu_temp[2*EQUATIONS+i] + b54*finavalu_temp[3*EQUATIONS+i]);
            }
        }
        else if(j==5){
            timeinst_temp = timeinst+a6*h;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b61*finavalu_temp[0*EQUATIONS+i] + b64*finavalu_temp[3*EQUATIONS+i] + b65*finavalu_temp[4*EQUATIONS+i]);
            }
        }
        else if(j==6){
            timeinst_temp = timeinst+a7*h;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b71*finavalu_temp[0*EQUATIONS+i] + b74*finavalu_temp[3*EQUATIONS+i] + b75*finavalu_temp[4*EQUATIONS+i] + b76*finavalu_temp[5*EQUATIONS+i]);
            }
        }
        else if(j==7){
            timeinst_temp = timeinst+a8*h;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b81*finavalu_temp[0*EQUATIONS+i] + b85*finavalu_temp[4*EQUATIONS+i] + b86*finavalu_temp[5*EQUATIONS+i] + b87*finavalu_temp[6*EQUATIONS+i]);
            }
        }
        else if(j==8){
            timeinst_temp = timeinst+a9*h;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b91*finavalu_temp[0*EQUATIONS+i] + b94*finavalu_temp[3*EQUATIONS+i] + b95*finavalu_temp[4*EQUATIONS+i] + b96*finavalu_temp[5*EQUATIONS+i] + b97*finavalu_temp[6*EQUATIONS+i]+ b98*finavalu_temp[7*EQUATIONS+i]);
            }
        }
        else if(j==9){
            timeinst_temp = timeinst+a10*h;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b10_1*finavalu_temp[0*EQUATIONS+i] + b10_4*finavalu_temp[3*EQUATIONS+i] + b10_5*finavalu_temp[4*EQUATIONS+i] + b10_6*finavalu_temp[5*EQUATIONS+i] + b10_7*finavalu_temp[6*EQUATIONS+i] + b10_8*finavalu_temp[7*EQUATIONS+i] + b10_9*finavalu_temp[8*EQUATIONS+i]);
            }
        }
        else if(j==10){
            timeinst_temp = timeinst+h;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b11_1*finavalu_temp[0*EQUATIONS+i] + b11_4*finavalu_temp[3*EQUATIONS+i] + b11_5*finavalu_temp[4*EQUATIONS+i] + b11_6*finavalu_temp[5*EQUATIONS+i] + b11_7*finavalu_temp[6*EQUATIONS+i] + b11_8*finavalu_temp[7*EQUATIONS+i] + b11_9*finavalu_temp[8*EQUATIONS+i]+ b11_10 * finavalu_temp[9*EQUATIONS+i]);
            }
        }
        else if(j==11){
            timeinst_temp = timeinst;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b12_1*finavalu_temp[0*EQUATIONS+i] + b12_6*finavalu_temp[5*EQUATIONS+i] + b12_7*finavalu_temp[6*EQUATIONS+i] + b12_8*finavalu_temp[7*EQUATIONS+i] + b12_9*finavalu_temp[8*EQUATIONS+i] + b12_10 * finavalu_temp[9*EQUATIONS+i]);
            }
        }
        else if(j==12){
            timeinst_temp = timeinst+h;
            for(i=0; i<EQUATIONS; i++){
                initvalu_temp[i] = initvalu[i] + h * ( b13_1*finavalu_temp[0*EQUATIONS+i] + b13_4*finavalu_temp[3*EQUATIONS+i] + b13_5*finavalu_temp[4*EQUATIONS+i] + b13_6*finavalu_temp[5*EQUATIONS+i] + b13_7*finavalu_temp[6*EQUATIONS+i] + b13_8*finavalu_temp[7*EQUATIONS+i] + b13_9*finavalu_temp[8*EQUATIONS+i] + b13_10*finavalu_temp[9*EQUATIONS+i] + finavalu_temp[11*EQUATIONS+i]);
            }
        }

        kernel_2_func(timeinst_temp,
                      initvalu_temp,
                      parameter,
                      &finavalu_temp[j*EQUATIONS],
                      com);
    }

    for(i=0; i<EQUATIONS; i++){
        finavalu[i]= initvalu[i] +  h * (c_1_11 * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i])  + c6 * finavalu_temp[5*EQUATIONS+i] + c_7_8 * (finavalu_temp[6*EQUATIONS+i] + finavalu_temp[7*EQUATIONS+i]) + c_9_10 * (finavalu_temp[8*EQUATIONS+i] + finavalu_temp[9*EQUATIONS+i]) );
    }

    for(i=0; i<EQUATIONS; i++){
        error[i] = fabs(err_factor * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i] - finavalu_temp[11*EQUATIONS+i] - finavalu_temp[12*EQUATIONS+i]));
    }
}

__kernel void solver_2(int workload,
                       int xmax,
                       __global fp* x,
                       __global fp* y,
                       __global fp* params,
                       __global fp* com,
                       __global fp* err,
                       __global fp* scale,
                       __global fp* yy,
                       __global fp* initvalu_temp,
                       __global fp* finavalu_temp){

    int tid = get_global_id(0);

    long y_pointer_initial;
    long y_pointer_current;
    long x_pointer_current;
    int err_pointer;
    int scale_pointer;
    int yy_pointer;
    int params_pointer;
    int initvalu_temp_pointer;
    int finavalu_temp_pointer;
    int com_pointer;

    fp err_exponent;
    fp h_init;
    fp h;
    fp tolerance;
    int xmin;

    int error_flag;
    int outside;
    fp scale_min;
    fp scale_fina;

    int i, j, k;

    err_pointer = tid*EQUATIONS;
    scale_pointer = tid*EQUATIONS;
    yy_pointer = tid*EQUATIONS;
    params_pointer = tid*PARAMETERS;
    initvalu_temp_pointer = tid*EQUATIONS;
    finavalu_temp_pointer = tid*13*EQUATIONS;
    com_pointer = tid*3;

    err_exponent = 1.0f / 7.0f;
    h_init = 1.0f;
    h = h_init;
    xmin = 0;
    tolerance = 10.0f / (fp)(xmax - xmin);

    if (xmax < xmin || h <= 0.0f){
        return;
    }

    if (xmax == xmin){
        return;
    }

    if (h > (xmax - xmin) ) {
        h = (fp)xmax - (fp)xmin;
    }

    if(tid<workload){

        for(k=1; k<(xmax+1); k++) {

            y_pointer_initial = (long)tid*((xmax+1)*EQUATIONS)+(long)(k-1)*EQUATIONS;
            y_pointer_current = (long)tid*((xmax+1)*EQUATIONS)+(long)k*EQUATIONS;
            x_pointer_current = (long)tid*(xmax+1)+(long)k;

            x[x_pointer_current] = (fp)k;
            h = h_init;

            scale_fina = 1.0f;

            for (j = 0; j < ATTEMPTS; j++) {

                error_flag = 0;
                outside = 0;
                scale_min = MAX_SCALE_FACTOR;

                embedded_fehlberg_7_8_2(h,
                                        x[x_pointer_current],
                                        &y[y_pointer_initial],
                                        &y[y_pointer_current],
                                        &params[params_pointer],
                                        &err[err_pointer],
                                        &initvalu_temp[initvalu_temp_pointer],
                                        &finavalu_temp[finavalu_temp_pointer],
                                        &com[com_pointer]);

                for(i=0; i<EQUATIONS; i++){
                    if(err[err_pointer+i] > 0.0f){
                        error_flag = 1;
                    }
                }
                if (error_flag != 1) {
                    scale_fina = MAX_SCALE_FACTOR;
                    break;
                }

                for(i=0; i<EQUATIONS; i++){
                    if(y[y_pointer_initial+i] == 0.0f){
                        yy[yy_pointer+i] = tolerance;
                    }
                    else{
                        yy[yy_pointer+i] = fabs(y[y_pointer_initial+i]);
                    }
                    scale[scale_pointer+i] = 0.8f * pow( tolerance * yy[yy_pointer+i] / err[err_pointer+i] , err_exponent );
                    if(scale[scale_pointer+i]<scale_min){
                        scale_min = scale[scale_pointer+i];
                    }
                }
                scale_fina = fmin(fmax(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

                for(i=0; i<EQUATIONS; i++){
                    if ( err[err_pointer+i] > ( tolerance * yy[yy_pointer+i] ) ){
                        outside = 1;
                    }
                }
                if (outside == 0){
                    break;
                }

                h = h * scale_fina;

                if (h >= 0.9f) {
                    h = 0.9f;
                }

                if ( x[x_pointer_current] + h > (fp)xmax ){
                    h = (fp)xmax - x[x_pointer_current];
                }
                else if ( x[x_pointer_current] + h + 0.5f * h > (fp)xmax ){
                    h = 0.5f * h;
                }
            }

            x[x_pointer_current] = x[x_pointer_current] + h;

            if ( j >= ATTEMPTS ) {
                return;
            }
        }
    }

    return;
}

__kernel void kernel(fp timeinst,
                     __global fp* d_initvalu,
                     __global fp* d_finavalu,
                     __global fp* d_params,
                     __global fp* d_com){

    int bx;
    int tx;

    int valu_offset;
    int params_offset;
    int com_offset;

    fp CaDyad;
    fp CaSL;
    fp CaCyt;

    bx = get_group_id(0);
    tx = get_local_id(0);

    if(bx == 0){
        if(tx == 0){
            valu_offset = 0;
            kernel_ecc_func(timeinst,
                            d_initvalu,
                            d_finavalu,
                            valu_offset,
                            d_params);
        }
    }
    else if(bx == 1){
        if(tx == 0){
            valu_offset = 46;
            params_offset = 0;
            com_offset = 0;
            CaDyad = d_initvalu[35]*1e3f;

            kernel_cam_func(timeinst,
                            d_initvalu,
                            d_finavalu,
                            valu_offset,
                            d_params,
                            params_offset,
                            d_com,
                            com_offset,
                            CaDyad);

            valu_offset = 61;
            params_offset = 5;
            com_offset = 1;
            CaSL = d_initvalu[36]*1e3f;

            kernel_cam_func(timeinst,
                            d_initvalu,
                            d_finavalu,
                            valu_offset,
                            d_params,
                            params_offset,
                            d_com,
                            com_offset,
                            CaSL);

            valu_offset = 76;
            params_offset = 10;
            com_offset = 2;
            CaCyt = d_initvalu[37]*1e3f;

            kernel_cam_func(timeinst,
                            d_initvalu,
                            d_finavalu,
                            valu_offset,
                            d_params,
                            params_offset,
                            d_com,
                            com_offset,
                            CaCyt);
        }
    }
}
